import{_ as e,c as t,o as a,a1 as i}from"./chunks/framework.TuIRSVI8.js";const u=JSON.parse('{"title":"Testing & Quality Gates","description":"","frontmatter":{},"headers":[],"relativePath":"TESTING.md","filePath":"TESTING.md","lastUpdated":1766422993000}'),n={name:"TESTING.md"};function l(o,s,r,p,h,d){return a(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="testing-quality-gates" tabindex="-1">Testing &amp; Quality Gates <a class="header-anchor" href="#testing-quality-gates" aria-label="Permalink to &quot;Testing &amp; Quality Gates&quot;">​</a></h1><p><em>Last reviewed: 2025‑12‑16 • Stack: BATS (bash) testing zsh functions</em></p><h2 id="snapshot" tabindex="-1">Snapshot <a class="header-anchor" href="#snapshot" aria-label="Permalink to &quot;Snapshot&quot;">​</a></h2><ul><li><strong>Files:</strong> 57 (23 unit, 13 integration, 11 root helpers/examples/templates, 10 misc)</li><li><strong>Approx tests:</strong> 700+ (majority unit; integration covers shell startup, chezmoi workflows, wrappers)</li><li><strong>Runtime:</strong> <code>make test</code> ~60–90s on laptop; <code>run-parallel.sh</code> trims to ~30s if GNU parallel present.</li></ul><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><ul><li><strong>Risk‑weighted:</strong> Cover daily drivers first (wrappers, auth, doctor, install/update).</li><li><strong>Hybrid bash/zsh:</strong> BATS runs bash; we load zsh functions into bash. Most POSIX/zsh syntax works; unusual zshisms (<code>*(.)</code>, <code>\${(U)var}</code>) need guards or shellcheck disables.</li><li><strong>Deterministic:</strong> No network calls; fixtures/mocks only. Prefer explicit env setup/teardown in <code>tests/test_helper.bash</code>.</li><li><strong>Portable:</strong> Tests avoid macOS/Linux‑only assumptions unless explicitly gated.</li></ul><h2 id="architecture-mental-model" tabindex="-1">Architecture (mental model) <a class="header-anchor" href="#architecture-mental-model" aria-label="Permalink to &quot;Architecture (mental model)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chezmoi source (templates, data)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ render → target files (~/)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ unit tests   : functions in isolation (mocks)</span></span>
<span class="line"><span>        ├─ integration  : workflows (auth, chezmoi apply, shell startup)</span></span>
<span class="line"><span>        └─ smoke/examples: quick sanity demos</span></span></code></pre></div><h2 id="layers-coverage" tabindex="-1">Layers &amp; Coverage <a class="header-anchor" href="#layers-coverage" aria-label="Permalink to &quot;Layers &amp; Coverage&quot;">​</a></h2><ul><li><strong>Unit (<code>tests/unit/*.bats</code>)</strong> – core functions: <ul><li>smart wrappers (bat/ls/man), git helpers (root/undo/ignore), system utils (mkcd), doctor/reload/auth, install/update helpers, language helpers (mise/pyenv/python/node).</li></ul></li><li><strong>Integration (<code>tests/integration/*.bats</code>)</strong> – end‑to‑end flows: <ul><li>shell startup, chezmoi workflow, deployment, wrapper integration, auth paths, mise transparent wrappers.</li></ul></li><li><strong>Examples (<code>tests/examples/*.bats</code>)</strong> – tiny smoke tests / helper demos.</li><li><strong>Templates (<code>tests/templates/*.bats</code>)</strong> – starting points for new tests (unit/integration/edge).</li><li><strong>Helpers (<code>tests/helpers/*.bash</code>)</strong> – shared setup, assertions, mocks, loader for zsh functions.</li></ul><p>Known gaps (as of 2025‑12‑16):</p><ul><li>macOS‑only flows (e.g., Homebrew GUI installs) lightly covered.</li><li>Agent/MCP end‑to‑end is partly manual; only CLI helpers are unit tested.</li><li>Networked services (gh/op/cloud) stubbed; no live calls.</li></ul><h2 id="how-to-run" tabindex="-1">How to Run <a class="header-anchor" href="#how-to-run" aria-label="Permalink to &quot;How to Run&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># from repo root (fast path)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # all</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-unit</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # unit only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-integration</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># direct</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./tests/run-all.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # serial</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./tests/run-parallel.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # parallel if GNU parallel present</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./tests/run-unit.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # unit only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./tests/run-integration.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # integration only</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># single file / filtered</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bats</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/unit/smart_wrappers_test.bats</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bats</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;bat&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/unit/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.bats</span></span></code></pre></div><h2 id="command-→-test-map-top-surfaces" tabindex="-1">Command → Test Map (top surfaces) <a class="header-anchor" href="#command-→-test-map-top-surfaces" aria-label="Permalink to &quot;Command → Test Map (top surfaces)&quot;">​</a></h2><ul><li><code>dotfiles doctor</code> → <code>tests/unit/dotfiles_doctor_test.bats</code>, <code>tests/integration/dotfiles_command_test.bats</code></li><li><code>dotfiles auth</code> → <code>tests/unit/dotfiles_auth_test.bats</code>, <code>tests/integration/auth_integration_test.bats</code></li><li><code>dotfiles update</code> → <code>tests/unit/dotfiles_update_test.bats</code></li><li>Smart wrappers (<code>bat</code>, <code>ls</code>, <code>man</code>, <code>git-root</code>, <code>mkcd</code>) → <code>tests/unit/smart_wrappers_test.bats</code>, <code>tests/unit/git_utils_test.bats</code>, <code>tests/unit/system_utils_test.bats</code></li><li>Shell startup → <code>tests/integration/shell_startup_test.bats</code></li><li>mise transparent wrappers → <code>tests/unit/mise_transparent_wrappers_test.bats</code>, <code>tests/integration/mise_integration_test.bats</code></li></ul><h2 id="writing-a-new-test-cheat-sheet" tabindex="-1">Writing a New Test (cheat sheet) <a class="header-anchor" href="#writing-a-new-test-cheat-sheet" aria-label="Permalink to &quot;Writing a New Test (cheat sheet)&quot;">​</a></h2><ol><li>Copy a template from <code>tests/templates/</code> (unit/integration/edge).</li><li>Source the helper in the header:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">load</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;test_helper.bash&#39;</span></span></code></pre></div></li><li>If loading a zsh file with z‑specific syntax, add comments like <code># shellcheck disable=SC2039</code> where needed.</li><li>Keep tests hermetic: create temp dirs, set env vars explicitly, avoid network.</li><li>Update descriptions to be actionable (“should … when …”).</li></ol><h2 id="quality-gates-to-keep" tabindex="-1">Quality gates to keep <a class="header-anchor" href="#quality-gates-to-keep" aria-label="Permalink to &quot;Quality gates to keep&quot;">​</a></h2><ul><li>Stay deterministic (no network, no host‑specific paths).</li><li>Prefer mocks over touching user config; if you must, use temp dirs.</li><li>Keep assertions readable; fail fast with context (<code>assert_contains</code> helpers).</li><li>When adding new surface areas (agents, VPN, chezmoi generators), add at least one unit + one integration path.</li></ul><h2 id="for-llm-agents" tabindex="-1">For LLM agents <a class="header-anchor" href="#for-llm-agents" aria-label="Permalink to &quot;For LLM agents&quot;">​</a></h2><ul><li>Use the <strong>public docs</strong> plus the test helper comments. Avoid linking to private paths from the public site; treat paths as code literals (<code>tests/unit/...</code>), not Markdown links, to keep builds green.</li><li>When editing or adding tests, keep changes in <code>~/.local/share/chezmoi</code> source tree; never in deployed files.</li></ul>`,22)])])}const g=e(n,[["render",l]]);export{u as __pageData,g as default};
